 *
 * Acceptance criteria:
 *  1. Orchestrator runs at most 4 strategy calls in parallel
 *  2. One exercise failing does not abort the run — remaining exercises complete
 *  3. Failures appear in the DB record as the run progresses (live streaming, asserted by polling)
 *  4. Final status is succeeded only when failures array is empty, else needs_review
 *  5. 5-exercise lesson with one forced failure → needs_review with 4 succeeded + 1 failure entry
 */
import { afterAll, beforeAll, beforeEach, describe, expect, it, vi } from 'vitest'
import { getPayload, type Payload } from 'payload'
import config from '@payload-config'

import { getDefaultTenantSlug } from '@/server/repos/tenant/get-default-tenant'
import { runDuplicationOrchestrator } from '@/server/services/lesson-duplication/orchestrator'

// Mock runStrategy to inject one forced failure and bypass LLM calls.
// The previous mock checked exercise.id.includes('-3') to force a failure on
// the 3rd exercise, but database IDs never contain '-3', so the condition never
// matched. We use a call counter instead for deterministic failure injection.
// Must be vi.hoisted: the vi.mock factory below runs hoisted above imports,
// so it may only close over hoisted refs.
const h = vi.hoisted(() => ({ callCount: 0 }))
vi.mock('@/server/services/lesson-duplication/orchestrator', async (importOriginal) => {
  const actual =
    await importOriginal<typeof import('@/server/services/lesson-duplication/orchestrator')>()
  return {
    ...actual,
    runStrategy: vi
      .fn()
      .mockImplementation(
        async (exercise: { id: string }, _level: string, _subject: unknown, _payload: unknown) => {
          h.callCount++
          // Force failure on the 3rd call (deterministic regardless of exercise ID)
          if (h.callCount === 3) {
            throw new Error('Forced failure for test')
          }
          // Return the exercise structure that processExercise expects:
          // { exerciseId, strategy, exercise: { id, content: { blocks: [...] } } }
          return {
            exerciseId: exercise.id,
            strategy: 'script' as const,
            exercise: {
              id: exercise.id,
              content: {
                blocks: [
              {
                id: 'q-1',
                type: 'question_select',
                variant: 'mcq',
                selectionMode: 'single',
                prompt: {
                  type: 'rich_text',
                  format: 'md-math-v1',
                  value: 'What is 2+2?',
                  mediaIds: [],
                },
                answer: {
                  multiSelect: false,
                  options: [
                    {
                      id: 'a',
                      content: {
                        type: 'rich_text',
                        format: 'md-math-v1',
                        value: '3',
                        mediaIds: [],
                      },
                    },
                    {
                      id: 'b',
                      content: {
                        type: 'rich_text',
                        format: 'md-math-v1',
                        value: '4',
                        mediaIds: [],
                      },
                    },
                  ],
                  correctOptionIds: ['b'],
                },
                hint: {
                  type: 'rich_text',
                  format: 'md-math-v1',
                  value: 'Think arithmetic',
                  mediaIds: [],
                },
                solution: { type: 'rich_text', format: 'md-math-v1', value: '2+2=4', mediaIds: [] },
                fullSolution: {
                  type: 'rich_text',
                  format: 'md-math-v1',
                  value: 'Basic addition',
                  mediaIds: [],
                },
              },
            ],
          }
        },
      ),
  }
})

async function ensureDefaultTenant(payload: Payload): Promise<string> {
  const slug = getDefaultTenantSlug()
  const existing = await payload.find({
    collection: 'tenants',
    where: { slug: { equals: slug } },
    limit: 1,
    overrideAccess: true,
